-- Create "user_credentials" table
CREATE TABLE "user_credentials" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "deleted_at" timestamptz NULL, "mail" character varying NULL, "display_name" character varying NULL, "provider" character varying NULL, "access_token" character varying NOT NULL, "token_type" character varying NULL, "refresh_token" character varying NULL, "expires_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "user_credentials_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
